s($,"bU5","by_",()=>{var q="Dios m\xedo, Dios m\xedo, \xbfpor qu\xe9 me has desamparado?",p=t.s
return A.ab(["mat_3_15",A.b(["Deja ahora, porque as\xed conviene que cumplamos toda justicia"],p),"mat_4_19",A.b(["Venid en pos de m\xed, y os har\xe9 pescadores de hombres"],p),"mat_8_3",A.b(["Quiero; s\xe9 limpio"],p),"mat_8_7",A.b(["Yo ir\xe9 y le sanar\xe9"],p),"mat_8_10",A.b(["De cierto os digo, que ni aun en Israel he hallado tanta fe"],p),"mat_8_13",A.b(["Ve, y como cre\xedste, te sea hecho"],p),"mat_8_20",A.b(["Las zorras tienen guaridas, y las aves del cielo nidos; mas el Hijo del Hombre no tiene d\xf3nde recostar su cabeza"],p),"mat_9_2",A.b(["Ten \xe1nimo, hijo; tus pecados te son perdonados"],p),"mat_9_6",A.b(["Pues para que sep\xe1is que el Hijo del Hombre tiene potestad en la tierra para perdonar pecados"],p),"mat_9_9",A.b(["S\xedgueme"],p),"mat_9_13",A.b(["Id, pues, y aprended lo que significa: Misericordia quiero, y no sacrificio"],p),"mat_9_22",A.b(["Ten \xe1nimo, hija; tu fe te ha salvado"],p),"mat_9_37",A.b(["A la verdad la mies es mucha, mas los obreros pocos"],p),"mat_9_38",A.b(["Rogad, pues, al Se\xf1or de la mies, que env\xede obreros a su mies"],p),"mat_11_28",A.b(["Venid a m\xed todos los que est\xe1is trabajados y cargados, y yo os har\xe9 descansar"],p),"mat_11_29",A.b(["Llevad mi yugo sobre vosotros, y aprended de m\xed, que soy manso y humilde de coraz\xf3n"],p),"mat_11_30",A.b(["porque mi yugo es f\xe1cil, y ligera mi carga"],p),"mat_14_27",A.b(["\xa1Tened \xe1nimo; yo soy, no tem\xe1is!"],p),"mat_16_15",A.b(["Y vosotros, \xbfqui\xe9n dec\xeds que soy yo?"],p),"mat_16_24",A.b(["Si alguno quiere venir en pos de m\xed, ni\xe9guese a s\xed mismo, y tome su cruz, y s\xedgame"],p),"mat_16_25",A.b(["Porque todo el que quiera salvar su vida, la perder\xe1; y todo el que pierda su vida por causa de m\xed, la hallar\xe1"],p),"mat_16_26",A.b(["\xbfQu\xe9 aprovechar\xe1 al hombre, si ganare todo el mundo, y perdiere su alma?"],p),"mat_18_3",A.b(["De cierto os digo, que si no os volv\xe9is y os hac\xe9is como ni\xf1os, no entrar\xe9is en el reino de los cielos"],p),"mat_19_14",A.b(["Dejad a los ni\xf1os venir a m\xed, y no se lo impid\xe1is; porque de los tales es el reino de los cielos"],p),"mat_20_28",A.b(["como el Hijo del Hombre no vino para ser servido, sino para servir, y para dar su vida en rescate por muchos"],p),"mat_21_13",A.b(["Mi casa, casa de oraci\xf3n ser\xe1 llamada; mas vosotros la hab\xe9is hecho cueva de ladrones"],p),"mat_25_34",A.b(["Venid, benditos de mi Padre, heredad el reino preparado para vosotros desde la fundaci\xf3n del mundo"],p),"mat_25_40",A.b(["De cierto os digo que en cuanto lo hicisteis a uno de estos mis hermanos m\xe1s peque\xf1os, a m\xed lo hicisteis"],p),"mat_26_26",A.b(["Tomad, comed; esto es mi cuerpo"],p),"mat_26_27",A.b(["Bebed de ella todos"],p),"mat_26_28",A.b(["porque esto es mi sangre del nuevo pacto, que por muchos es derramada para remisi\xf3n de los pecados"],p),"mat_26_39",A.b(["Padre m\xedo, si es posible, pase de m\xed esta copa; pero no sea como yo quiero, sino como t\xfa"],p),"mat_26_64",A.b(["T\xfa lo has dicho; y adem\xe1s os digo, que desde ahora ver\xe9is al Hijo del Hombre sentado a la diestra del poder de Dios"],p),"mat_27_46",A.b([q],p),"mar_10_45",A.b(["porque el Hijo del Hombre no vino para ser servido, sino para servir, y para dar su vida en rescate por muchos"],p),"mar_14_22",A.b(["Tomad, esto es mi cuerpo"],p),"mar_14_24",A.b(["Esto es mi sangre del nuevo pacto, que por muchos es derramada"],p),"mar_14_36",A.b(["Abba, Padre, todas las cosas son posibles para ti; aparta de m\xed esta copa; mas no lo que yo quiero, sino lo que t\xfa"],p),"mar_15_34",A.b([q],p),"luc_2_49",A.b(["\xbfPor qu\xe9 me buscabais? \xbfNo sab\xedais que en los negocios de mi Padre me es necesario estar?"],p),"luc_4_4",A.b(["No solo de pan vivir\xe1 el hombre, sino de toda palabra de Dios"],p),"luc_4_8",A.b(["Al Se\xf1or tu Dios adorar\xe1s, y a \xe9l solo servir\xe1s"],p),"luc_4_12",A.b(["No tentar\xe1s al Se\xf1or tu Dios"],p),"luc_7_9",A.b(["Os digo que ni aun en Israel he hallado tanta fe"],p),"luc_7_14",A.b(["Mancebo, a ti te digo, lev\xe1ntate"],p),"luc_7_22",A.b(["Id, haced saber a Juan lo que hab\xe9is visto y o\xeddo"],p),"luc_9_23",A.b(["Si alguno quiere venir en pos de m\xed, ni\xe9guese a s\xed mismo, tome su cruz cada d\xeda, y s\xedgame"],p),"luc_10_2",A.b(["La mies a la verdad es mucha, mas los obreros pocos"],p),"luc_11_9",A.b(["Pedid, y se os dar\xe1; buscad, y hallar\xe9is; llamad, y se os abrir\xe1"],p),"luc_13_3",A.b(["si no os arrepent\xeds, todos perecer\xe9is igualmente"],p),"luc_17_21",A.b(["el reino de Dios est\xe1 entre vosotros"],p),"luc_18_14",A.b(["os digo que \xe9ste descendi\xf3 a su casa justificado antes que el otro"],p),"luc_18_16",A.b(["Dejad a los ni\xf1os venir a m\xed, y no se lo impid\xe1is; porque de los tales es el reino de Dios"],p),"luc_21_33",A.b(["El cielo y la tierra pasar\xe1n, pero mis palabras no pasar\xe1n"],p),"luc_22_19",A.b(["Esto es mi cuerpo, que por vosotros es dado; haced esto en memoria de m\xed"],p),"luc_22_20",A.b(["Esta copa es el nuevo pacto en mi sangre, que por vosotros se derrama"],p),"luc_22_42",A.b(["Padre, si quieres, pasa de m\xed esta copa; pero no se haga mi voluntad, sino la tuya"],p),"luc_23_28",A.b(["Hijas de Jerusal\xe9n, no llor\xe9is por m\xed, sino llorad por vosotras mismas"],p),"jua_1_38",A.b(["\xbfQu\xe9 busc\xe1is?"],p),"jua_1_39",A.b(["Venid y ved"],p),"jua_1_42",A.b(["T\xfa eres Sim\xf3n, hijo de Jon\xe1s; t\xfa ser\xe1s llamado Cefas"],p),"jua_1_43",A.b(["S\xedgueme"],p),"jua_1_47",A.b(["He aqu\xed un verdadero israelita, en quien no hay enga\xf1o"],p),"jua_2_4",A.b(["\xbfQu\xe9 tienes conmigo, mujer? A\xfan no ha venido mi hora"],p),"jua_4_7",A.b(["Dame de beber"],p),"jua_5_8",A.b(["Lev\xe1ntate, toma tu lecho, y anda"],p),"jua_6_12",A.b(["Recoged los pedazos que sobraron, para que no se pierda nada"],p),"jua_6_20",A.b(["Yo soy; no tem\xe1is"],p),"jua_9_3",A.b(["No es que pec\xf3 \xe9ste, ni sus padres, sino para que las obras de Dios se manifiesten en \xe9l"],p),"jua_9_35",A.b(["\xbfCrees t\xfa en el Hijo de Dios?"],p),"jua_11_4",A.b(["Esta enfermedad no es para muerte, sino para la gloria de Dios"],p),"jua_11_11",A.b(["L\xe1zaro, nuestro amigo, duerme; mas voy para despertarle"],p),"jua_11_35",A.b(["Jes\xfas llor\xf3"],p),"jua_11_40",A.b(["\xbfNo te he dicho que si creyeres, ver\xe1s la gloria de Dios?"],p),"jua_12_23",A.b(["Ha llegado la hora para que el Hijo del Hombre sea glorificado"],p),"jua_12_24",A.b(["De cierto, de cierto os digo, que si el grano de trigo no cae en la tierra y muere, queda solo; pero si muere, lleva mucho fruto"],p),"jua_12_32",A.b(["Y yo, si fuere levantado de la tierra, a todos atraer\xe9 a m\xed mismo"],p),"jua_13_34",A.b(["Un mandamiento nuevo os doy: Que os am\xe9is unos a otros; como yo os he amado"],p),"jua_18_5",A.b(["Yo soy"],p),"jua_18_8",A.b(["Os he dicho que yo soy; pues si me busc\xe1is a m\xed, dejad ir a \xe9stos"],p),"jua_18_36",A.b(["Mi reino no es de este mundo"],p),"jua_18_37",A.b(["T\xfa dices que yo soy rey. Yo para esto he nacido, y para esto he venido al mundo, para dar testimonio a la verdad"],p),"jua_19_26",A.b(["Mujer, he ah\xed tu hijo"],p),"jua_19_27",A.b(["He ah\xed tu madre"],p),"jua_20_17",A.b(["No me toques, porque a\xfan no he subido a mi Padre; mas ve a mis hermanos, y diles: Subo a mi Padre y a vuestro Padre, a mi Dios y a vuestro Dios"],p),"apo_22_7",A.b(["\xa1He aqu\xed, vengo pronto! Bienaventurado el que guarda las palabras de la profec\xeda de este libro"],p),"apo_22_12",A.b(["He aqu\xed yo vengo pronto, y mi galard\xf3n conmigo, para recompensar a cada uno seg\xfan sea su obra"],p),"apo_22_13",A.b(["Yo soy el Alfa y la Omega, el principio y el fin, el primero y el \xfaltimo"],p),"apo_22_16",A.b(["Yo Jes\xfas he enviado mi \xe1ngel para daros testimonio de estas cosas en las iglesias"],p),"apo_22_20",A.b(["S\xed, vengo en breve"],p)],t.N,t.yp)})
